tln("\u8FDE\u7EED " + k + " \u4E2A\u5143\u7D20\u7684\u6700\u5927\u548C\u4E3A\uFF1A" + maxSum); // \u8F93\u51FA\uFF1A16\n    }\n}\n'})}),"\n",(0,i.jsx)(e.h2,{id:"\u53EF\u53D8\u7A97\u53E3\u5927\u5C0F",children:"\u53EF\u53D8\u7A97\u53E3\u5927\u5C0F"}),"\n",(0,i.jsx)(e.pre,{children:(0,i.jsx)(e.code,{className:"language-java",children:'package com.jasper.slidethewindow;\n\n/**\n * @version 1.0\n * @Author jasper\n * @Date 2025-01-09\n * @Description \u7ED9\u5B9A\u4E00\u4E2A\u6B63\u6574\u6570\u6570\u7EC4 nums \u548C\u4E00\u4E2A\u6B63\u6574\u6570 target\uFF0C\u627E\u5230 nums \u4E2D\u548C\u4E3A target \u7684\u6700\u77ED\u8FDE\u7EED\u5B50\u6570\u7EC4\uFF0C\u5E76\u8FD4\u56DE\u5176\u957F\u5EA6\u3002\u5982\u679C\u4E0D\u5B58\u5728\u8FD9\u6837\u7684\u5B50\u6570\u7EC4\uFF0C\u5219\u8FD4\u56DE 0\u3002\n */\npublic class Demo2 {\n\n    /**\n     * \u53EF\u53D8\u7A97\u53E3\u5927\u5C0F \u4ECE\u5DE6\u5F80\u53F3\u4E00\u76F4\u52A0   \u5927\u4E8Etarget\u4E86  \u5DE6\u8FB9\u4E00\u76F4\u51CF \u51CF\u5230\u5C0F\u4E8Etarget\u4E86 \u53F3\u8FB9\u518D\u52A0   length = right-left+1\n     * @param nums\n     * @param target\n     * @return\n     */\n    public static int minSubArrayLen(int[] nums,int target){\n        int left = 0;\n        int right = 0;\n        int minLen = Integer.MAX_VALUE;\n        int sum = 0;\n        while (right < nums.length){\n            sum += nums[right];\n            while (sum>=target){\n                sum -= nums[left];\n                minLen = Math.min(minLen,right-left+1);\n                left++;\n            }\n            right++;\n        }\n        return minLen == Integer.MAX_VALUE ? 0 : minLen;\n    }\n    public static void main(String[] args) {\n        int[] nums1 = {2, 3, 1, 2, 4, 3};\n        int target1 = 7;\n        System.out.println("\u6700\u77ED\u5B50\u6570\u7EC4\u957F\u5EA6\uFF1A" + minSubArrayLen(nums1, target1)); // \u8F93\u51FA\uFF1A2\n\n        int[] nums2 = {1, 4, 4};\n        int target2 = 4;\n        System.out.println("\u6700\u77ED\u5B50\u6570\u7EC4\u957F\u5EA6\uFF1A" + minSubArrayLen(nums2, target2)); // \u8F93\u51FA\uFF1A1\n\n        int[] nums3 = {1,1,1,1,1,1};\n        int target3 = 10;\n        System.out.println("\u6700\u77ED\u5B50\u6570\u7EC4\u957F\u5EA6\uFF1A" + minSubArrayLen(nums3, target3)); // \u8F93\u51FA\uFF1A0\n    }\n}\n\n'})})]})}function d(n={}){let{wrapper:e}={...(0,a.R)(),...n.components};return e?(0,i.jsx)(e,{...n,children:(0,i.jsx)(o,{...n})}):o(n)}},28453(n,e,t){t.d(e,{R:()=>s,x:()=>u});var r=t(96540);let i={},a=r.createContext(i);function s(n){let e=r.useContext(a);return r.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function u(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(i):n.components||i:s(n.components),r.createElement(a.Provider,{value:e},n.children)}}}]);